window.KJV1769_STRONG_BOOKS["1John"] = {"osis":"1John","book":"요한일서","verses":{"1:1":{"text":"That which was from the beginning, which we have heard, which we have seen with our eyes, which we have looked upon, and our hands have handled, of the Word of life;","words":[["G3739","That which",0,10],["G2258","was",11,14],["G0575","from",15,19],["G0746","the beginning",20,33],["G3739","which",35,40],["G0191","we have heard",41,54],["G3739","which",56,61],["G3708","we have seen",62,74],["G2257","with our",75,83],["G3788","eyes",84,88],["G3739","which",90,95],["G2300","we have looked upon",96,115],["G2532","and",117,120],["G2257","our",121,124],["G5495","hands",125,130],["G5584","have handled",131,143],["G4012","of",145,147],["G3056","the Word",148,156],["G2222","of life",157,164]]},"1:2":{"text":"(For the life was manifested, and we have seen it, and bear witness, and shew unto you that eternal life, which was with the Father, and was manifested unto us;)","words":[["G2532","(For",0,4],["G2222","the life",5,13],["G5319","was manifested",14,28],["G2532","and",30,33],["G3708","we have seen",34,46],["G2532","it, and",47,54],["G3140","bear witness",55,67],["G2532","and",69,72],["G0518","shew",73,77],["G5213","unto you",78,86],["G0166","that eternal",87,99],["G2222","life",100,104],["G3748","which",106,111],["G2258","was",112,115],["G4314","with",116,120],["G3962","the Father",121,131],["G2532","and",133,136],["G5319","was manifested",137,151],["G2254","unto us",152,159]]},"1:3":{"text":"That which we have seen and heard declare we unto you, that ye also may have fellowship with us: and truly our fellowship is with the Father, and with his Son Jesus Christ.","words":[["G3739","That which",0,10],["G3708","we have seen",11,23],["G2532","and",24,27],["G0191","heard",28,33],["G0518","declare we",34,44],["G5213","unto you",45,53],["G2443","that",55,59],["G5210","ye",60,62],["G2532","also",63,67],["G2192","may have",68,76],["G2842","fellowship",77,87],["G3326","with",88,92],["G2257","us",93,95],["G2532","and",97,100],["G2251","truly our",101,110],["G2842","fellowship",111,121],["G1161","fellowship",111,121],["G3326","is with",122,129],["G3962","the Father",130,140],["G2532","and",142,145],["G3326","with",146,150],["G0846","his",151,154],["G5207","Son",155,158],["G2424","Jesus",159,164],["G5547","Christ",165,171]]},"1:4":{"text":"And these things write we unto you, that your joy may be full.","words":[["G2532","And",0,3],["G5023","these things",4,16],["G1125","write we",17,25],["G5213","unto you",26,34],["G2443","that",36,40],["G5216","your",41,45],["G5479","joy",46,49],["G5600","may be",50,56],["G4137","full",57,61]]},"1:5":{"text":"This then is the message which we have heard of him, and declare unto you, that God is light, and in him is no darkness at all.","words":[["G3778","This",0,4],["G2532","then",5,9],["G2076","is",10,12],["G1860","the message",13,24],["G3739","which",25,30],["G0191","we have heard",31,44],["G0575","of",45,47],["G0846","him",48,51],["G2532","and",53,56],["G0312","declare",57,64],["G5213","unto you",65,73],["G3754","that",75,79],["G2316","God",80,83],["G2076","is",84,86],["G5457","light",87,92],["G2532","and",94,97],["G1722","in",98,100],["G0846","him",101,104],["G2076","is",105,107],["G3756","no",108,110],["G4653","darkness",111,119],["G3762","at all",120,126]]},"1:6":{"text":"If we say that we have fellowship with him, and walk in darkness, we lie, and do not the truth:","words":[["G1437","If",0,2],["G2036","we say",3,9],["G3754","that",10,14],["G2192","we have",15,22],["G2842","fellowship",23,33],["G3326","with",34,38],["G0846","him",39,42],["G2532","and",44,47],["G4043","walk",48,52],["G1722","in",53,55],["G4655","darkness",56,64],["G5574","we lie",66,72],["G2532","and",74,77],["G4160","do",78,80],["G3756","not",81,84],["G0225","the truth",85,94]]},"1:7":{"text":"But if we walk in the light, as he is in the light, we have fellowship one with another, and the blood of Jesus Christ his Son cleanseth us from all sin.","words":[["G1161","But",0,3],["G1437","if",4,6],["G4043","we walk",7,14],["G1722","in",15,17],["G5457","the light",18,27],["G5613","as",29,31],["G0846","he",32,34],["G2076","is",35,37],["G1722","in",38,40],["G5457","the light",41,50],["G2192","we have",52,59],["G2842","fellowship",60,70],["G3326","one with another",71,87],["G0240","one with another",71,87],["G2532","and",89,92],["G0129","the blood",93,102],["G2424","of Jesus",103,111],["G5547","Christ",112,118],["G0846","his",119,122],["G5207","Son",123,126],["G2511","cleanseth",127,136],["G2248","us",137,139],["G0575","from",140,144],["G3956","all",145,148],["G0266","sin",149,152]]},"1:8":{"text":"If we say that we have no sin, we deceive ourselves, and the truth is not in us.","words":[["G1437","If",0,2],["G2036","we say",3,9],["G3754","that",10,14],["G2192","we have",15,22],["G3756","no",23,25],["G0266","sin",26,29],["G4105","we deceive",31,41],["G1438","ourselves",42,51],["G2532","and",53,56],["G0225","the truth",57,66],["G2076","is",67,69],["G3756","not",70,73],["G1722","in",74,76],["G2254","us",77,79]]},"1:9":{"text":"If we confess our sins, he is faithful and just to forgive us our sins, and to cleanse us from all unrighteousness.","words":[["G1437","If",0,2],["G3670","we confess",3,13],["G2257","our",14,17],["G0266","sins",18,22],["G2076","he is",24,29],["G4103","faithful",30,38],["G2532","and",39,42],["G1342","just",43,47],["G2443","to",48,50],["G0863","forgive",51,58],["G2254","us",59,61],["G0266","our sins",62,70],["G2532","and",72,75],["G2511","to cleanse",76,86],["G2248","us",87,89],["G0575","from",90,94],["G3956","all",95,98],["G0093","unrighteousness",99,114]]},"1:10":{"text":"If we say that we have not sinned, we make him a liar, and his word is not in us.","words":[["G1437","If",0,2],["G2036","we say",3,9],["G3754","that",10,14],["G0264","we have",15,22],["G3756","not",23,26],["G0264","sinned",27,33],["G4160","we make",35,42],["G0846","him",43,46],["G5583","a liar",47,53],["G2532","and",55,58],["G0846","his",59,62],["G3056","word",63,67],["G2076","is",68,70],["G3756","not",71,74],["G1722","in",75,77],["G2254","us",78,80]]},"2:1":{"text":"My little children, these things write I unto you, that ye sin not. And if any man sin, we have an advocate with the Father, Jesus Christ the righteous:","words":[["G3450","My",0,2],["G5040","little children",3,18],["G5023","these things",20,32],["G1125","write I",33,40],["G5213","unto you",41,49],["G3363","that",51,55],["G0264","ye sin",56,62],["G3363","not",63,66],["G2532","And",68,71],["G1437","if",72,74],["G5100","any man",75,82],["G0264","sin",83,86],["G2192","we have",88,95],["G3875","an advocate",96,107],["G4314","with",108,112],["G3962","the Father",113,123],["G2424","Jesus",125,130],["G5547","Christ",131,137],["G1342","the righteous",138,151]]},"2:2":{"text":"And he is the propitiation for our sins: and not for ours only, but also for the sins of the whole world.","words":[["G2532","And",0,3],["G0846","he",4,6],["G2076","is",7,9],["G2434","the propitiation",10,26],["G4012","for",27,30],["G2257","our",31,34],["G0266","sins",35,39],["G1161","and",41,44],["G3756","not",45,48],["G4012","for",49,52],["G2251","ours",53,57],["G3440","only",58,62],["G0235","but",64,67],["G2532","also",68,72],["G4012","for",73,76],["G3650","the sins of the whole",77,98],["G2889","world",99,104]]},"2:3":{"text":"And hereby we do know that we know him, if we keep his commandments.","words":[["G2532","And",0,3],["G1722","hereby",4,10],["G5129","hereby",4,10],["G1097","we do know",11,21],["G3754","that",22,26],["G1097","we know",27,34],["G0846","him",35,38],["G1437","if",40,42],["G5083","we keep",43,50],["G0846","his",51,54],["G1785","commandments",55,67]]},"2:4":{"text":"He that saith, I know him, and keepeth not his commandments, is a liar, and the truth is not in him.","words":[["G3004","He that saith",0,13],["G1097","I know",15,21],["G0846","him",22,25],["G2532","and",27,30],["G5083","keepeth",31,38],["G3361","not",39,42],["G0846","his",43,46],["G1785","commandments",47,59],["G2076","is",61,63],["G5583","a liar",64,70],["G2532","and",72,75],["G0225","the truth",76,85],["G2076","is",86,88],["G3756","not",89,92],["G1722","in",93,95],["G5129","him",96,99]]},"2:5":{"text":"But whoso keepeth his word, in him verily is the love of God perfected: hereby know we that we are in him.","words":[["G1161","But",0,3],["G3739","whoso",4,9],["G0302","keepeth",10,17],["G5083","keepeth",10,17],["G0846","his",18,21],["G3056","word",22,26],["G1722","in",28,30],["G5129","him",31,34],["G0230","verily",35,41],["G5048","is",42,44],["G0026","the love",45,53],["G2316","of God",54,60],["G5048","perfected",61,70],["G1722","hereby",72,78],["G5129","hereby",72,78],["G1097","know we",79,86],["G3754","that",87,91],["G2070","we are",92,98],["G1722","in",99,101],["G0846","him",102,105]]},"2:6":{"text":"He that saith he abideth in him ought himself also so to walk, even as he walked.","words":[["G3004","He that saith",0,13],["G3306","he abideth",14,24],["G1722","in",25,27],["G0846","him",28,31],["G3784","ought",32,37],["G0846","himself",38,45],["G2532","also",46,50],["G3779","so",51,53],["G4043","to walk",54,61],["G2531","even as",63,70],["G1565","he",71,73],["G4043","walked",74,80]]},"2:7":{"text":"Brethren, I write no new commandment unto you, but an old commandment which ye had from the beginning. The old commandment is the word which ye have heard from the beginning.","words":[["G0080","Brethren",0,8],["G1125","I write",10,17],["G3756","no",18,20],["G2537","new",21,24],["G1785","commandment",25,36],["G5213","unto you",37,45],["G0235","but",47,50],["G3820","an old",51,57],["G1785","commandment",58,69],["G3739","which",70,75],["G2192","ye had",76,82],["G0575","from",83,87],["G0746","the beginning",88,101],["G3820","The old",103,110],["G1785","commandment",111,122],["G2076","is",123,125],["G3056","the word",126,134],["G3739","which",135,140],["G0191","ye have heard",141,154],["G0575","from",155,159],["G0746","the beginning",160,173]]},"2:8":{"text":"Again, a new commandment I write unto you, which thing is true in him and in you: because the darkness is past, and the true light now shineth.","words":[["G3825","Again",0,5],["G2537","a new",7,12],["G1785","commandment",13,24],["G1125","I write",25,32],["G5213","unto you",33,41],["G3739","which thing",43,54],["G2076","is",55,57],["G0227","true",58,62],["G1722","in",63,65],["G0846","him",66,69],["G2532","and",70,73],["G1722","in",74,76],["G5213","you",77,80],["G3754","because",82,89],["G4653","the darkness",90,102],["G3855","is past",103,110],["G2532","and",112,115],["G0228","the true",116,124],["G5457","light",125,130],["G2235","now",131,134],["G5316","shineth",135,142]]},"2:9":{"text":"He that saith he is in the light, and hateth his brother, is in darkness even until now.","words":[["G3004","He that saith",0,13],["G1511","he is",14,19],["G1722","in",20,22],["G5457","the light",23,32],["G2532","and",34,37],["G3404","hateth",38,44],["G0846","his",45,48],["G0080","brother",49,56],["G2076","is",58,60],["G1722","in",61,63],["G4653","darkness",64,72],["G2193","even until",73,83],["G0737","now",84,87]]},"2:10":{"text":"He that loveth his brother abideth in the light, and there is none occasion of stumbling in him.","words":[["G0025","He that loveth",0,14],["G0846","his",15,18],["G0080","brother",19,26],["G3306","abideth",27,34],["G1722","in",35,37],["G5457","the light",38,47],["G2532","and",49,52],["G2076","there is",53,61],["G3756","none",62,66],["G4625","occasion of stumbling",67,88],["G1722","in",89,91],["G0846","him",92,95]]},"2:11":{"text":"But he that hateth his brother is in darkness, and walketh in darkness, and knoweth not whither he goeth, because that darkness hath blinded his eyes.","words":[["G1161","But",0,3],["G3404","he that hateth",4,18],["G0846","his",19,22],["G0080","brother",23,30],["G2076","is",31,33],["G1722","in",34,36],["G4653","darkness",37,45],["G2532","and",47,50],["G4043","walketh",51,58],["G1722","in",59,61],["G4653","darkness",62,70],["G2532","and",72,75],["G1492","knoweth",76,83],["G3756","not",84,87],["G4226","whither",88,95],["G5217","he goeth",96,104],["G3754","because",106,113],["G4653","that darkness",114,127],["G5186","hath blinded",128,140],["G0846","his",141,144],["G3788","eyes",145,149]]},"2:12":{"text":"I write unto you, little children, because your sins are forgiven you for his name's sake.","words":[["G1125","I write",0,7],["G5213","unto you",8,16],["G5040","little children",18,33],["G3754","because",35,42],["G0266","your sins",43,52],["G0863","are forgiven",53,65],["G5213","you",66,69],["G1223","for",70,73],["G0846","his",74,77],["G3686","name's",78,84],["G1223","sake",85,89]]},"2:13":{"text":"I write unto you, fathers, because ye have known him that is from the beginning. I write unto you, young men, because ye have overcome the wicked one. I write unto you, little children, because ye have known the Father.","words":[["G1125","I write",0,7],["G5213","unto you",8,16],["G3962","fathers",18,25],["G3754","because",27,34],["G1097","ye have known",35,48],["G0575","him that is from",49,65],["G0746","the beginning",66,79],["G1125","I write",81,88],["G5213","unto you",89,97],["G3495","young men",99,108],["G3754","because",110,117],["G3528","ye have overcome",118,134],["G4190","the wicked one",135,149],["G1125","I write",151,158],["G5213","unto you",159,167],["G3813","little children",169,184],["G3754","because",186,193],["G1097","ye have known",194,207],["G3962","the Father",208,218]]},"2:14":{"text":"I have written unto you, fathers, because ye have known him that is from the beginning. I have written unto you, young men, because ye are strong, and the word of God abideth in you, and ye have overcome the wicked one.","words":[["G1125","I have written",0,14],["G5213","unto you",15,23],["G3962","fathers",25,32],["G3754","because",34,41],["G1097","ye have known",42,55],["G0575","him that is from",56,72],["G0746","the beginning",73,86],["G1125","I have written",88,102],["G5213","unto you",103,111],["G3495","young men",113,122],["G3754","because",124,131],["G2075","ye are",132,138],["G2478","strong",139,145],["G2532","and",147,150],["G3056","the word",151,159],["G2316","of God",160,166],["G3306","abideth",167,174],["G1722","in",175,177],["G5213","you",178,181],["G2532","and",183,186],["G3528","ye have overcome",187,203],["G4190","the wicked one",204,218]]},"2:15":{"text":"Love not the world, neither the things that are in the world. If any man love the world, the love of the Father is not in him.","words":[["G0025","Love",0,4],["G3361","not",5,8],["G2889","the world",9,18],["G3366","neither",20,27],["G1722","the things that are in",28,50],["G2889","the world",51,60],["G1437","If",62,64],["G5100","any man",65,72],["G0025","love",73,77],["G2889","the world",78,87],["G0026","the love",89,97],["G3962","of the Father",98,111],["G2076","is",112,114],["G3756","not",115,118],["G1722","in",119,121],["G0846","him",122,125]]},"2:16":{"text":"For all that is in the world, the lust of the flesh, and the lust of the eyes, and the pride of life, is not of the Father, but is of the world.","words":[["G3754","For",0,3],["G3956","all",4,7],["G1722","that is in",8,18],["G2889","the world",19,28],["G1939","the lust",30,38],["G4561","of the flesh",39,51],["G2532","and",53,56],["G1939","the lust",57,65],["G3788","of the eyes",66,77],["G2532","and",79,82],["G0212","the pride",83,92],["G0979","of life",93,100],["G2076","is",102,104],["G3756","not",105,108],["G1537","of",109,111],["G3962","the Father",112,122],["G0235","but",124,127],["G2076","is",128,130],["G1537","of",131,133],["G2889","the world",134,143]]},"2:17":{"text":"And the world passeth away, and the lust thereof: but he that doeth the will of God abideth for ever.","words":[["G2532","And",0,3],["G2889","the world",4,13],["G3855","passeth away",14,26],["G2532","and",28,31],["G1939","the lust",32,40],["G0846","thereof",41,48],["G1161","but",50,53],["G4160","he that doeth",54,67],["G2307","the will",68,76],["G2316","of God",77,83],["G3306","abideth",84,91],["G1519","for",92,95],["G0165","ever",96,100]]},"2:18":{"text":"Little children, it is the last time: and as ye have heard that antichrist shall come, even now are there many antichrists; whereby we know that it is the last time.","words":[["G3813","Little children",0,15],["G2076","it is",17,22],["G2078","the last",23,31],["G5610","time",32,36],["G2532","and",38,41],["G2531","as",42,44],["G0191","ye have heard",45,58],["G3754","that",59,63],["G0500","antichrist",64,74],["G2064","shall come",75,85],["G2532","even",87,91],["G3568","now",92,95],["G1096","are there",96,105],["G4183","many",106,110],["G0500","antichrists",111,122],["G3606","whereby",124,131],["G1097","we know",132,139],["G3754","that",140,144],["G2076","it is",145,150],["G2078","the last",151,159],["G5610","time",160,164]]},"2:19":{"text":"They went out from us, but they were not of us; for if they had been of us, they would no doubt have continued with us: but they went out, that they might be made manifest that they were not all of us.","words":[["G1831","They went out",0,13],["G1537","from",14,18],["G2257","us",19,21],["G0235","but",23,26],["G2258","they were",27,36],["G3756","not",37,40],["G1537","of",41,43],["G2257","us",44,46],["G1063","for",48,51],["G1487","if",52,54],["G2258","they had been",55,68],["G1537","of",69,71],["G2257","us",72,74],["G0302","they would",76,86],["G3306","no doubt have continued",87,110],["G3326","with",111,115],["G2257","us",116,118],["G0235","but",120,123],["G2443","they went out, that",124,143],["G5319","they might be made manifest",144,171],["G3754","that",172,176],["G1526","they were",177,186],["G3756","not",187,190],["G3956","all",191,194],["G1537","of",195,197],["G2257","us",198,200]]},"2:20":{"text":"But ye have an unction from the Holy One, and ye know all things.","words":[["G2532","But",0,3],["G5210","ye",4,6],["G2192","have",7,11],["G5545","an unction",12,22],["G0575","from",23,27],["G0040","the Holy One",28,40],["G2532","and",42,45],["G1492","ye know",46,53],["G3956","all things",54,64]]},"2:21":{"text":"I have not written unto you because ye know not the truth, but because ye know it, and that no lie is of the truth.","words":[["G1125","I have",0,6],["G3756","not",7,10],["G1125","written",11,18],["G5213","unto you",19,27],["G3754","because",28,35],["G1492","ye know",36,43],["G3756","not",44,47],["G0225","the truth",48,57],["G0235","but",59,62],["G3754","because",63,70],["G1492","ye know",71,78],["G0846","it",79,81],["G2532","and",83,86],["G3754","that",87,91],["G3956","no",92,94],["G3756","no",92,94],["G5579","lie",95,98],["G2076","is",99,101],["G1537","of",102,104],["G0225","the truth",105,114]]},"2:22":{"text":"Who is a liar but he that denieth that Jesus is the Christ? He is antichrist, that denieth the Father and the Son.","words":[["G5101","Who",0,3],["G2076","is",4,6],["G5583","a liar",7,13],["G1508","but",14,17],["G0720","he that denieth",18,33],["G3754","that",34,38],["G2424","Jesus",39,44],["G2076","is",45,47],["G3756","is",45,47],["G5547","the Christ",48,58],["G3778","He",60,62],["G2076","is",63,65],["G0500","antichrist",66,76],["G0720","that denieth",78,90],["G3962","the Father",91,101],["G2532","and",102,105],["G5207","the Son",106,113]]},"2:23":{"text":"Whosoever denieth the Son, the same hath not the Father: (but) he that acknowledgeth the Son hath the Father also.","words":[["G3956","Whosoever",0,9],["G0720","denieth",10,17],["G5207","the Son",18,25],["G2192","the same hath",27,40],["G3761","not",41,44],["G3962","the Father",45,55],["G3670","(but) he that acknowledgeth",57,84],["G5207","the Son",85,92],["G2192","hath",93,97],["G3962","the Father",98,108],["G2532","also",109,113]]},"2:24":{"text":"Let that therefore abide in you, which ye have heard from the beginning. If that which ye have heard from the beginning shall remain in you, ye also shall continue in the Son, and in the Father.","words":[["G3306","Let",0,3],["G3767","that therefore",4,18],["G3306","abide",19,24],["G1722","in",25,27],["G5213","you",28,31],["G3739","which",33,38],["G5210","ye",39,41],["G0191","have heard",42,52],["G0575","from",53,57],["G0746","the beginning",58,71],["G1437","If",73,75],["G3739","that which",76,86],["G0191","ye have heard",87,100],["G0575","from",101,105],["G0746","the beginning",106,119],["G3306","shall remain",120,132],["G1722","in",133,135],["G5213","you",136,139],["G5210","ye",141,143],["G2532","also",144,148],["G3306","shall continue",149,163],["G1722","in",164,166],["G5207","the Son",167,174],["G2532","and",176,179],["G1722","in",180,182],["G3962","the Father",183,193]]},"2:25":{"text":"And this is the promise that he hath promised us, even eternal life.","words":[["G2532","And",0,3],["G3778","this",4,8],["G2076","is",9,11],["G1860","the promise",12,23],["G3739","that",24,28],["G0846","he",29,31],["G1861","hath promised",32,45],["G2254","us",46,48],["G0166","even eternal",50,62],["G2222","life",63,67]]},"2:26":{"text":"These things have I written unto you concerning them that seduce you.","words":[["G5023","These",0,5],["G1125","things have I written",6,27],["G5213","unto you",28,36],["G4012","concerning",37,47],["G4105","them that seduce",48,64],["G5209","you",65,68]]},"2:27":{"text":"But the anointing which ye have received of him abideth in you, and ye need not that any man teach you: but as the same anointing teacheth you of all things, and is truth, and is no lie, and even as it hath taught you, ye shall abide in him.","words":[["G2532","But",0,3],["G5545","the anointing",4,17],["G3739","which",18,23],["G5210","ye",24,26],["G2983","have received",27,40],["G0575","of",41,43],["G0846","him",44,47],["G3306","abideth",48,55],["G1722","in",56,58],["G5213","you",59,62],["G2532","and",64,67],["G5532","ye need",68,75],["G2192","ye need",68,75],["G3756","not",76,79],["G2443","that",80,84],["G5100","any man",85,92],["G1321","teach",93,98],["G5209","you",99,102],["G0235","but",104,107],["G5613","as",108,110],["G0846","the same",111,119],["G5545","anointing",120,129],["G1321","teacheth",130,138],["G5209","you",139,142],["G4012","of",143,145],["G3956","all things",146,156],["G2532","and",158,161],["G2076","is",162,164],["G0227","truth",165,170],["G2532","and",172,175],["G2076","is",176,178],["G3756","no",179,181],["G5579","lie",182,185],["G2532","and",187,190],["G2531","even as",191,198],["G1321","it hath taught",199,213],["G5209","you",214,217],["G3306","ye shall abide",219,233],["G1722","in",234,236],["G0846","him",237,240]]},"2:28":{"text":"And now, little children, abide in him; that, when he shall appear, we may have confidence, and not be ashamed before him at his coming.","words":[["G2532","And",0,3],["G3568","now",4,7],["G5040","little children",9,24],["G3306","abide",26,31],["G1722","in",32,34],["G0846","him",35,38],["G2443","that",40,44],["G3752","when",46,50],["G5319","he shall appear",51,66],["G2192","we may have",68,79],["G3954","confidence",80,90],["G2532","and",92,95],["G3361","not",96,99],["G0153","be ashamed",100,110],["G0575","before",111,117],["G0846","him",118,121],["G1722","at",122,124],["G0846","his",125,128],["G3952","coming",129,135]]},"2:29":{"text":"If ye know that he is righteous, ye know that every one that doeth righteousness is born of him.","words":[["G1437","If",0,2],["G1492","ye know",3,10],["G3754","that",11,15],["G2076","he is",16,21],["G1342","righteous",22,31],["G1097","ye know",33,40],["G3754","that",41,45],["G3956","every one",46,55],["G4160","that doeth",56,66],["G1343","righteousness",67,80],["G1080","is born",81,88],["G1537","of",89,91],["G0846","him",92,95]]},"3:1":{"text":"Behold, what manner of love the Father hath bestowed upon us, that we should be called the sons of God: therefore the world knoweth us not, because it knew him not.","words":[["G1492","Behold",0,6],["G4217","what manner",8,19],["G0026","of love",20,27],["G3962","the Father",28,38],["G1325","hath bestowed",39,52],["G2254","upon us",53,60],["G2443","that",62,66],["G2564","we should be called",67,86],["G5043","the sons",87,95],["G2316","of God",96,102],["G1223","therefore",104,113],["G5124","therefore",104,113],["G2889","the world",114,123],["G1097","knoweth",124,131],["G2248","us",132,134],["G3756","not",135,138],["G3754","because",140,147],["G1097","it knew",148,155],["G0846","him",156,159],["G3756","not",160,163]]},"3:2":{"text":"Beloved, now are we the sons of God, and it doth not yet appear what we shall be: but we know that, when he shall appear, we shall be like him; for we shall see him as he is.","words":[["G0027","Beloved",0,7],["G3568","now",9,12],["G2070","are we",13,19],["G5043","the sons",20,28],["G2316","of God",29,35],["G2532","and",37,40],["G5319","it doth",41,48],["G3768","not yet",49,56],["G5319","appear",57,63],["G5101","what",64,68],["G2071","we shall be",69,80],["G1161","but",82,85],["G1492","we know",86,93],["G3754","that",94,98],["G1437","when",100,104],["G5319","he shall appear",105,120],["G2071","we shall be",122,133],["G3664","like",134,138],["G0846","him",139,142],["G3754","for",144,147],["G3700","we shall see",148,160],["G0846","him",161,164],["G2531","as",165,167],["G2076","he is",168,173]]},"3:3":{"text":"And every man that hath this hope in him purifieth himself, even as he is pure.","words":[["G2532","And",0,3],["G3956","every man",4,13],["G2192","that hath",14,23],["G5026","this",24,28],["G1680","hope",29,33],["G1909","in",34,36],["G0846","him",37,40],["G0048","purifieth",41,50],["G1438","himself",51,58],["G2531","even as",60,67],["G1565","he",68,70],["G2076","is",71,73],["G0053","pure",74,78]]},"3:4":{"text":"Whosoever committeth sin transgresseth also the law: for sin is the transgression of the law.","words":[["G3956","Whosoever",0,9],["G4160","committeth",10,20],["G0266","sin",21,24],["G4160","transgresseth",25,38],["G0458","transgresseth",25,38],["G2532","also",39,43],["G0458","the law",44,51],["G2532","for",53,56],["G0266","sin",57,60],["G2076","is",61,63],["G0458","the transgression of the law",64,92]]},"3:5":{"text":"And ye know that he was manifested to take away our sins; and in him is no sin.","words":[["G2532","And",0,3],["G1492","ye know",4,11],["G3754","that",12,16],["G1565","he",17,19],["G5319","was manifested",20,34],["G2443","to",35,37],["G0142","take away",38,47],["G2257","our",48,51],["G0266","sins",52,56],["G2532","and",58,61],["G1722","in",62,64],["G0846","him",65,68],["G2076","is",69,71],["G3756","no",72,74],["G0266","sin",75,78]]},"3:6":{"text":"Whosoever abideth in him sinneth not: whosoever sinneth hath not seen him, neither known him.","words":[["G3956","Whosoever",0,9],["G3306","abideth",10,17],["G1722","in",18,20],["G0846","him",21,24],["G0264","sinneth",25,32],["G3756","not",33,36],["G3956","whosoever",38,47],["G0264","sinneth",48,55],["G3708","hath",56,60],["G3756","not",61,64],["G3708","seen",65,69],["G0846","him",70,73],["G3761","neither",75,82],["G1097","known",83,88],["G0846","him",89,92]]},"3:7":{"text":"Little children, let no man deceive you: he that doeth righteousness is righteous, even as he is righteous.","words":[["G5040","Little children",0,15],["G4105","let",17,20],["G3367","no man",21,27],["G4105","deceive",28,35],["G5209","you",36,39],["G4160","he that doeth",41,54],["G1343","righteousness",55,68],["G2076","is",69,71],["G1342","righteous",72,81],["G2531","even as",83,90],["G1565","he",91,93],["G2076","is",94,96],["G1342","righteous",97,106]]},"3:8":{"text":"He that committeth sin is of the devil; for the devil sinneth from the beginning. For this purpose the Son of God was manifested, that he might destroy the works of the devil.","words":[["G4160","He that committeth",0,18],["G0266","sin",19,22],["G2076","is",23,25],["G1537","of",26,28],["G1228","the devil",29,38],["G3754","for",40,43],["G1228","the devil",44,53],["G0264","sinneth",54,61],["G0575","from",62,66],["G0746","the beginning",67,80],["G1519","For",82,85],["G5124","this purpose",86,98],["G5207","the Son",99,106],["G2316","of God",107,113],["G5319","was manifested",114,128],["G2443","that",130,134],["G3089","he might destroy",135,151],["G2041","the works",152,161],["G1228","of the devil",162,174]]},"3:9":{"text":"Whosoever is born of God doth not commit sin; for his seed remaineth in him: and he cannot sin, because he is born of God.","words":[["G3956","Whosoever",0,9],["G1080","is born",10,17],["G1537","of",18,20],["G2316","God",21,24],["G4160","doth",25,29],["G3756","not",30,33],["G0266","commit sin",34,44],["G3754","for",46,49],["G0846","his",50,53],["G4690","seed",54,58],["G3306","remaineth",59,68],["G1722","in",69,71],["G0846","him",72,75],["G2532","and",77,80],["G3756","he cannot",81,90],["G1410","he cannot",81,90],["G0264","sin",91,94],["G3754","because",96,103],["G1080","he is born",104,114],["G1537","of",115,117],["G2316","God",118,121]]},"3:10":{"text":"In this the children of God are manifest, and the children of the devil: whosoever doeth not righteousness is not of God, neither he that loveth not his brother.","words":[["G1722","In",0,2],["G5129","this",3,7],["G5043","the children",8,20],["G2316","of God",21,27],["G2076","are",28,31],["G5318","manifest",32,40],["G2532","and",42,45],["G5043","the children",46,58],["G1228","of the devil",59,71],["G3956","whosoever",73,82],["G4160","doeth",83,88],["G3361","not",89,92],["G1343","righteousness",93,106],["G2076","is",107,109],["G3756","not",110,113],["G1537","of",114,116],["G2316","God",117,120],["G2532","neither",122,129],["G0025","he that loveth",130,144],["G3361","not",145,148],["G0846","his",149,152],["G0080","brother",153,160]]},"3:11":{"text":"For this is the message that ye heard from the beginning, that we should love one another.","words":[["G3754","For",0,3],["G3778","this",4,8],["G2076","is",9,11],["G0031","the message",12,23],["G3739","that",24,28],["G0191","ye heard",29,37],["G0575","from",38,42],["G0746","the beginning",43,56],["G2443","that",58,62],["G0025","we should love",63,77],["G0240","one another",78,89]]},"3:12":{"text":"Not as Cain, who was of that wicked one, and slew his brother. And wherefore slew he him? Because his own works were evil, and his brother's righteous.","words":[["G3756","Not",0,3],["G2531","as",4,6],["G2535","Cain",7,11],["G2258","who was",13,20],["G1537","of",21,23],["G4190","that wicked one",24,39],["G2532","and",41,44],["G4969","slew",45,49],["G0846","his",50,53],["G0080","brother",54,61],["G2532","And",63,66],["G5484","wherefore",67,76],["G5101","wherefore",67,76],["G4969","slew",77,81],["G0846","he him",82,88],["G3754","Because",90,97],["G0846","his own",98,105],["G2041","works",106,111],["G2258","were",112,116],["G4190","evil",117,121],["G1161","and",123,126],["G0846","his",127,130],["G0080","brother's",131,140],["G1342","righteous",141,150]]},"3:13":{"text":"Marvel not, my brethren, if the world hate you.","words":[["G2296","Marvel",0,6],["G3361","not",7,10],["G3450","my",12,14],["G0080","brethren",15,23],["G1487","if",25,27],["G2889","the world",28,37],["G3404","hate",38,42],["G5209","you",43,46]]},"3:14":{"text":"We know that we have passed from death unto life, because we love the brethren. He that loveth not his brother abideth in death.","words":[["G1492","We know",0,7],["G3754","that",8,12],["G2249","we",13,15],["G3327","have passed",16,27],["G1537","from",28,32],["G2288","death",33,38],["G1519","unto",39,43],["G2222","life",44,48],["G3754","because",50,57],["G0025","we love",58,65],["G0080","the brethren",66,78],["G0025","He that loveth",80,94],["G3361","not",95,98],["G0080","his brother",99,110],["G3306","abideth",111,118],["G1722","in",119,121],["G2288","death",122,127]]},"3:15":{"text":"Whosoever hateth his brother is a murderer: and ye know that no murderer hath eternal life abiding in him.","words":[["G3956","Whosoever",0,9],["G3404","hateth",10,16],["G0846","his",17,20],["G0080","brother",21,28],["G2076","is",29,31],["G0443","a murderer",32,42],["G2532","and",44,47],["G1492","ye know",48,55],["G3754","that",56,60],["G3756","no",61,63],["G3956","no",61,63],["G0443","murderer",64,72],["G2192","hath",73,77],["G0166","eternal",78,85],["G2222","life",86,90],["G3306","abiding",91,98],["G1722","in",99,101],["G0846","him",102,105]]},"3:16":{"text":"Hereby perceive we the love of God, because he laid down his life for us: and we ought to lay down our lives for the brethren.","words":[["G1722","Hereby",0,6],["G5129","Hereby",0,6],["G1097","perceive we",7,18],["G0026","the love",19,27],["G3754","of God, because",28,43],["G1565","he",44,46],["G5087","laid down",47,56],["G0846","his",57,60],["G5590","life",61,65],["G5228","for",66,69],["G2257","us",70,72],["G2532","and",74,77],["G2249","we",78,80],["G3784","ought",81,86],["G5087","to lay down",87,98],["G5590","our lives",99,108],["G5228","for",109,112],["G0080","the brethren",113,125]]},"3:17":{"text":"But whoso hath this world's good, and seeth his brother have need, and shutteth up his bowels of compassion from him, how dwelleth the love of God in him?","words":[["G1161","But",0,3],["G3739","whoso",4,9],["G0302","whoso",4,9],["G2192","hath",10,14],["G2889","this world's",15,27],["G0979","good",28,32],["G2532","and",34,37],["G2334","seeth",38,43],["G0846","his",44,47],["G0080","brother",48,55],["G2192","have",56,60],["G5532","need",61,65],["G2532","and",67,70],["G2808","shutteth up",71,82],["G0846","his",83,86],["G4698","bowels",87,93],["G0575","of compassion from",94,112],["G0846","him",113,116],["G4459","how",118,121],["G3306","dwelleth",122,130],["G0026","the love",131,139],["G2316","of God",140,146],["G1722","in",147,149],["G0846","him",150,153]]},"3:18":{"text":"My little children, let us not love in word, neither in tongue; but in deed and in truth.","words":[["G3450","My",0,2],["G5040","little children",3,18],["G0025","let us",20,26],["G3361","not",27,30],["G0025","love",31,35],["G3056","in word",36,43],["G3366","neither",45,52],["G1100","in tongue",53,62],["G0235","but",64,67],["G2041","in deed",68,75],["G2532","and",76,79],["G0225","in truth",80,88]]},"3:19":{"text":"And hereby we know that we are of the truth, and shall assure our hearts before him.","words":[["G2532","And",0,3],["G1722","hereby",4,10],["G5129","hereby",4,10],["G1097","we know",11,18],["G3754","that",19,23],["G2070","we are",24,30],["G1537","of",31,33],["G0225","the truth",34,43],["G2532","and",45,48],["G3982","shall assure",49,61],["G2257","our",62,65],["G2588","hearts",66,72],["G1715","before",73,79],["G0846","him",80,83]]},"3:20":{"text":"For if our heart condemn us, God is greater than our heart, and knoweth all things.","words":[["G3754","For",0,3],["G1437","if",4,6],["G2257","our",7,10],["G2588","heart",11,16],["G2607","condemn us",17,27],["G3754","",-1,-1],["G2316","God",29,32],["G2076","is",33,35],["G3187","greater",36,43],["G2257","than our",44,52],["G2588","heart",53,58],["G2532","and",60,63],["G1097","knoweth",64,71],["G3956","all things",72,82]]},"3:21":{"text":"Beloved, if our heart condemn us not, then have we confidence toward God.","words":[["G0027","Beloved",0,7],["G3362","if",9,11],["G2257","our",12,15],["G2588","heart",16,21],["G2607","condemn",22,29],["G2257","us",30,32],["G3362","not",33,36],["G2192","then have we",38,50],["G3954","confidence",51,61],["G4314","toward",62,68],["G2316","God",69,72]]},"3:22":{"text":"And whatsoever we ask, we receive of him, because we keep his commandments, and do those things that are pleasing in his sight.","words":[["G2532","And",0,3],["G3739","whatsoever",4,14],["G1437","whatsoever",4,14],["G0154","we ask",15,21],["G2983","we receive",23,33],["G3844","of",34,36],["G0846","him",37,40],["G3754","because",42,49],["G5083","we keep",50,57],["G0846","his",58,61],["G1785","commandments",62,74],["G2532","and",76,79],["G4160","do",80,82],["G0701","those things that are pleasing",83,113],["G0846","in his",114,120],["G1799","sight",121,126]]},"3:23":{"text":"And this is his commandment, That we should believe on the name of his Son Jesus Christ, and love one another, as he gave us commandment.","words":[["G2532","And",0,3],["G3778","this",4,8],["G2076","is",9,11],["G0846","his",12,15],["G1785","commandment",16,27],["G2443","That",29,33],["G4100","we should believe",34,51],["G3686","on the name",52,63],["G0846","of his",64,70],["G5207","Son",71,74],["G2424","Jesus",75,80],["G5547","Christ",81,87],["G2532","and",89,92],["G0025","love",93,97],["G0240","one another",98,109],["G2531","as",111,113],["G1325","he gave",114,121],["G2254","us",122,124],["G1785","commandment",125,136]]},"3:24":{"text":"And he that keepeth his commandments dwelleth in him, and he in him. And hereby we know that he abideth in us, by the Spirit which he hath given us.","words":[["G2532","And",0,3],["G5083","he that keepeth",4,19],["G0846","his",20,23],["G1785","commandments",24,36],["G3306","dwelleth",37,45],["G1722","in",46,48],["G0846","him",49,52],["G2532","and",54,57],["G0846","he",58,60],["G1722","in",61,63],["G0846","him",64,67],["G2532","And",69,72],["G1722","hereby",73,79],["G5129","hereby",73,79],["G1097","we know",80,87],["G3754","that",88,92],["G3306","he abideth",93,103],["G1722","in",104,106],["G2254","us",107,109],["G1537","by",111,113],["G4151","the Spirit",114,124],["G3739","which",125,130],["G1325","he hath given",131,144],["G2254","us",145,147]]},"4:1":{"text":"Beloved, believe not every spirit, but try the spirits whether they are of God: because many false prophets are gone out into the world.","words":[["G0027","Beloved",0,7],["G4100","believe",9,16],["G3361","not",17,20],["G3956","every",21,26],["G4151","spirit",27,33],["G0235","but",35,38],["G1381","try",39,42],["G4151","the spirits",43,54],["G1487","whether",55,62],["G2076","they are",63,71],["G1537","of",72,74],["G2316","God",75,78],["G3754","because",80,87],["G4183","many",88,92],["G5578","false prophets",93,107],["G1831","are gone out",108,120],["G1519","into",121,125],["G2889","the world",126,135]]},"4:2":{"text":"Hereby know ye the Spirit of God: Every spirit that confesseth that Jesus Christ is come in the flesh is of God:","words":[["G1722","Hereby",0,6],["G3739","Hereby",0,6],["G5129","Hereby",0,6],["G1097","know ye",7,14],["G4151","the Spirit",15,25],["G2316","of God",26,32],["G3956","Every",34,39],["G4151","spirit",40,46],["G3670","that confesseth",47,62],["G2424","that Jesus",63,73],["G5547","Christ",74,80],["G2064","is come",81,88],["G1722","in",89,91],["G4561","the flesh",92,101],["G2076","is",102,104],["G1537","of",105,107],["G2316","God",108,111]]},"4:3":{"text":"And every spirit that confesseth not that Jesus Christ is come in the flesh is not of God: and this is that spirit of antichrist, whereof ye have heard that it should come; and even now already is it in the world.","words":[["G2532","And",0,3],["G3956","every",4,9],["G4151","spirit",10,16],["G3739","that",17,21],["G3670","confesseth",22,32],["G3361","not",33,36],["G2424","that Jesus",37,47],["G5547","Christ",48,54],["G2064","is come",55,62],["G1722","in",63,65],["G4561","the flesh",66,75],["G2076","is",76,78],["G3756","not",79,82],["G1537","of",83,85],["G2316","God",86,89],["G2532","and",91,94],["G5124","this",95,99],["G2076","is",100,102],["G0500","that spirit of antichrist",103,128],["G3739","whereof",130,137],["G0191","ye have heard",138,151],["G3754","that",152,156],["G2064","it should come",157,171],["G2532","and even",173,181],["G3568","now",182,185],["G2235","already",186,193],["G2076","is it",194,199],["G1722","in",200,202],["G2889","the world",203,212]]},"4:4":{"text":"Ye are of God, little children, and have overcome them: because greater is he that is in you, than he that is in the world.","words":[["G5210","Ye",0,2],["G2075","are",3,6],["G1537","of",7,9],["G2316","God",10,13],["G5040","little children",15,30],["G2532","and",32,35],["G3528","have overcome",36,49],["G0846","them",50,54],["G3754","because",56,63],["G3187","greater",64,71],["G2076","is he that is",72,85],["G1722","in",86,88],["G5213","you",89,92],["G2228","than",94,98],["G1722","he that is in",99,112],["G2889","the world",113,122]]},"4:5":{"text":"They are of the world: therefore speak they of the world, and the world heareth them.","words":[["G0846","They",0,4],["G1526","are",5,8],["G1537","of",9,11],["G2889","the world",12,21],["G1223","therefore",23,32],["G5124","therefore",23,32],["G2980","speak they",33,43],["G1537","of",44,46],["G2889","the world",47,56],["G2532","and",58,61],["G2889","the world",62,71],["G0191","heareth",72,79],["G0846","them",80,84]]},"4:6":{"text":"We are of God: he that knoweth God heareth us; he that is not of God heareth not us. Hereby know we the spirit of truth, and the spirit of error.","words":[["G2249","We",0,2],["G2070","are",3,6],["G1537","of",7,9],["G2316","God",10,13],["G1097","he that knoweth",15,30],["G2316","God",31,34],["G0191","heareth",35,42],["G2257","us",43,45],["G3739","he that",47,54],["G2076","is",55,57],["G3756","not",58,61],["G1537","of",62,64],["G2316","God",65,68],["G0191","heareth",69,76],["G3756","not",77,80],["G2257","us",81,83],["G1537","Hereby",85,91],["G5127","Hereby",85,91],["G1097","know we",92,99],["G4151","the spirit",100,110],["G0225","of truth",111,119],["G2532","and",121,124],["G4151","the spirit",125,135],["G4106","of error",136,144]]},"4:7":{"text":"Beloved, let us love one another: for love is of God; and every one that loveth is born of God, and knoweth God.","words":[["G0027","Beloved",0,7],["G0025","let us love",9,20],["G0240","one another",21,32],["G3754","for",34,37],["G0026","love",38,42],["G2076","is",43,45],["G1537","of",46,48],["G2316","God",49,52],["G2532","and",54,57],["G3956","every one",58,67],["G0025","that loveth",68,79],["G1080","is born",80,87],["G1537","of",88,90],["G2316","God",91,94],["G2532","and",96,99],["G1097","knoweth",100,107],["G2316","God",108,111]]},"4:8":{"text":"He that loveth not knoweth not God; for God is love.","words":[["G0025","He that loveth",0,14],["G3361","not",15,18],["G1097","knoweth",19,26],["G3756","not",27,30],["G2316","God",31,34],["G3754","for",36,39],["G2316","God",40,43],["G2076","is",44,46],["G0026","love",47,51]]},"4:9":{"text":"In this was manifested the love of God toward us, because that God sent his only begotten Son into the world, that we might live through him.","words":[["G1722","In",0,2],["G5129","this",3,7],["G5319","was manifested",8,22],["G0026","the love",23,31],["G2316","of God",32,38],["G1722","toward",39,45],["G2254","us",46,48],["G3754","because",50,57],["G2316","that God",58,66],["G0649","sent",67,71],["G0846","his",72,75],["G3439","only begotten",76,89],["G5207","Son",90,93],["G1519","into",94,98],["G2889","the world",99,108],["G2443","that",110,114],["G2198","we might live",115,128],["G1223","through",129,136],["G0846","him",137,140]]},"4:10":{"text":"Herein is love, not that we loved God, but that he loved us, and sent his Son to be the propitiation for our sins.","words":[["G1722","Herein",0,6],["G5129","Herein",0,6],["G2076","is",7,9],["G0026","love",10,14],["G3754","not",16,19],["G3756","that",20,24],["G2249","we",25,27],["G0025","loved",28,33],["G2316","God",34,37],["G0235","but",39,42],["G3754","that",43,47],["G0846","he",48,50],["G0025","loved",51,56],["G2248","us",57,59],["G2532","and",61,64],["G0649","sent",65,69],["G0846","his",70,73],["G5207","Son",74,77],["G2434","to be the propitiation",78,100],["G4012","for",101,104],["G2257","our",105,108],["G0266","sins",109,113]]},"4:11":{"text":"Beloved, if God so loved us, we ought also to love one another.","words":[["G0027","Beloved",0,7],["G1487","if",9,11],["G2316","God",12,15],["G3779","so",16,18],["G0025","loved",19,24],["G2248","us",25,27],["G2249","we",29,31],["G3784","ought",32,37],["G2532","also",38,42],["G0025","to love",43,50],["G0240","one another",51,62]]},"4:12":{"text":"No man hath seen God at any time. If we love one another, God dwelleth in us, and his love is perfected in us.","words":[["G3762","No man",0,6],["G2300","hath seen",7,16],["G2316","God",17,20],["G4455","at any time",21,32],["G1437","If",34,36],["G0025","we love",37,44],["G0240","one another",45,56],["G2316","God",58,61],["G3306","dwelleth",62,70],["G1722","in",71,73],["G2254","us",74,76],["G2532","and",78,81],["G0846","his",82,85],["G0026","love",86,90],["G2076","is",91,93],["G5048","perfected",94,103],["G1722","in",104,106],["G2254","us",107,109]]},"4:13":{"text":"Hereby know we that we dwell in him, and he in us, because he hath given us of his Spirit.","words":[["G1722","Hereby",0,6],["G5129","Hereby",0,6],["G1097","know we",7,14],["G3754","that",15,19],["G3306","we dwell",20,28],["G1722","in",29,31],["G0846","him",32,35],["G2532","and",37,40],["G0846","he",41,43],["G1722","in",44,46],["G2254","us",47,49],["G3754","because",51,58],["G1325","he hath given",59,72],["G2254","us",73,75],["G1537","of",76,78],["G0846","his",79,82],["G4151","Spirit",83,89]]},"4:14":{"text":"And we have seen and do testify that the Father sent the Son to be the Saviour of the world.","words":[["G2532","And",0,3],["G2249","we",4,6],["G2300","have seen",7,16],["G2532","and",17,20],["G3140","do testify",21,31],["G3754","that",32,36],["G3962","the Father",37,47],["G0649","sent",48,52],["G5207","the Son",53,60],["G4990","to be the Saviour",61,78],["G2889","of the world",79,91]]},"4:15":{"text":"Whosoever shall confess that Jesus is the Son of God, God dwelleth in him, and he in God.","words":[["G3739","Whosoever",0,9],["G0302","Whosoever",0,9],["G3670","shall confess",10,23],["G3754","that",24,28],["G2424","Jesus",29,34],["G2076","is",35,37],["G5207","the Son",38,45],["G2316","of God",46,52],["G2316","God",54,57],["G3306","dwelleth",58,66],["G1722","in",67,69],["G0846","him",70,73],["G2532","and",75,78],["G0846","he",79,81],["G1722","in",82,84],["G2316","God",85,88]]},"4:16":{"text":"And we have known and believed the love that God hath to us. God is love; and he that dwelleth in love dwelleth in God, and God in him.","words":[["G2532","And",0,3],["G2249","we",4,6],["G1097","have known",7,17],["G2532","and",18,21],["G4100","believed",22,30],["G0026","the love",31,39],["G3739","that",40,44],["G2316","God",45,48],["G2192","hath",49,53],["G1722","to",54,56],["G2254","us",57,59],["G2316","God",61,64],["G2076","is",65,67],["G0026","love",68,72],["G2532","and",74,77],["G3306","he that dwelleth",78,94],["G1722","in",95,97],["G0026","love",98,102],["G3306","dwelleth",103,111],["G1722","in",112,114],["G2316","God",115,118],["G2532","and",120,123],["G2316","God",124,127],["G1722","in",128,130],["G0846","him",131,134]]},"4:17":{"text":"Herein is our love made perfect, that we may have boldness in the day of judgment: because as he is, so are we in this world.","words":[["G1722","Herein",0,6],["G5129","Herein",0,6],["G3326","is our",7,13],["G2257","is our",7,13],["G0026","love",14,18],["G5048","made perfect",19,31],["G2443","that",33,37],["G2192","we may have",38,49],["G3954","boldness",50,58],["G1722","in",59,61],["G2250","the day",62,69],["G2920","of judgment",70,81],["G3754","because",83,90],["G2531","as",91,93],["G1565","he",94,96],["G2076","is",97,99],["G2532","so",101,103],["G2070","are",104,107],["G2249","we",108,110],["G1722","in",111,113],["G5129","this",114,118],["G2889","world",119,124]]},"4:18":{"text":"There is no fear in love; but perfect love casteth out fear: because fear hath torment. He that feareth is not made perfect in love.","words":[["G2076","There is",0,8],["G3756","no",9,11],["G5401","fear",12,16],["G1722","in",17,19],["G0026","love",20,24],["G0235","but",26,29],["G5046","perfect",30,37],["G0026","love",38,42],["G0906","casteth",43,50],["G1854","out",51,54],["G5401","fear",55,59],["G3754","because",61,68],["G5401","fear",69,73],["G2192","hath",74,78],["G2851","torment",79,86],["G1161","",-1,-1],["G5399","He that feareth",88,103],["G5048","is",104,106],["G3756","not",107,110],["G5048","made perfect",111,123],["G1722","in",124,126],["G0026","love",127,131]]},"4:19":{"text":"We love him, because he first loved us.","words":[["G2249","We",0,2],["G0025","love",3,7],["G0846","him",8,11],["G3754","because",13,20],["G0846","he",21,23],["G4413","first",24,29],["G0025","loved",30,35],["G2248","us",36,38]]},"4:20":{"text":"If a man say, I love God, and hateth his brother, he is a liar: for he that loveth not his brother whom he hath seen, how can he love God whom he hath not seen?","words":[["G1437","If",0,2],["G5100","a man",3,8],["G2036","say",9,12],["G3754","",-1,-1],["G0025","I love",14,20],["G2316","God",21,24],["G2532","and",26,29],["G3404","hateth",30,36],["G0846","his",37,40],["G0080","brother",41,48],["G2076","he is",50,55],["G5583","a liar",56,62],["G1063","for",64,67],["G0025","he that loveth",68,82],["G3361","not",83,86],["G0846","his",87,90],["G0080","brother",91,98],["G3739","whom",99,103],["G3708","he hath seen",104,116],["G4459","how",118,121],["G1410","can",122,125],["G0025","he love",126,133],["G2316","God",134,137],["G3739","whom",138,142],["G3708","he hath",143,150],["G3756","not",151,154],["G3708","seen",155,159]]},"4:21":{"text":"And this commandment have we from him, That he who loveth God love his brother also.","words":[["G2532","And",0,3],["G5026","this",4,8],["G1785","commandment",9,20],["G2192","have we",21,28],["G0575","from",29,33],["G0846","him",34,37],["G2443","That",39,43],["G0025","he who loveth",44,57],["G2316","God",58,61],["G0025","love",62,66],["G0846","his",67,70],["G0080","brother",71,78],["G2532","also",79,83]]},"5:1":{"text":"Whosoever believeth that Jesus is the Christ is born of God: and every one that loveth him that begat loveth him also that is begotten of him.","words":[["G3956","Whosoever",0,9],["G4100","believeth",10,19],["G3754","that",20,24],["G2424","Jesus",25,30],["G2076","is",31,33],["G5547","the Christ",34,44],["G1080","is born",45,52],["G1537","of",53,55],["G2316","God",56,59],["G2532","and",61,64],["G3956","every one",65,74],["G0025","that loveth",75,86],["G1080","him that begat",87,101],["G0025","loveth",102,108],["G2532","him also",109,117],["G1080","that is begotten",118,134],["G1537","of",135,137],["G0846","him",138,141]]},"5:2":{"text":"By this we know that we love the children of God, when we love God, and keep his commandments.","words":[["G1722","By",0,2],["G5129","this",3,7],["G1097","we know",8,15],["G3754","that",16,20],["G0025","we love",21,28],["G5043","the children",29,41],["G2316","of God",42,48],["G3752","when",50,54],["G0025","we love",55,62],["G2316","God",63,66],["G2532","and",68,71],["G5083","keep",72,76],["G0846","his",77,80],["G1785","commandments",81,93]]},"5:3":{"text":"For this is the love of God, that we keep his commandments: and his commandments are not grievous.","words":[["G1063","For",0,3],["G3778","this",4,8],["G2076","is",9,11],["G0026","the love",12,20],["G2316","of God",21,27],["G2443","that",29,33],["G5083","we keep",34,41],["G0846","his",42,45],["G1785","commandments",46,58],["G2532","and",60,63],["G0846","his",64,67],["G1785","commandments",68,80],["G1526","are",81,84],["G3756","not",85,88],["G0926","grievous",89,97]]},"5:4":{"text":"For whatsoever is born of God overcometh the world: and this is the victory that overcometh the world, even our faith.","words":[["G3754","For",0,3],["G3956","whatsoever",4,14],["G1080","is born",15,22],["G1537","of",23,25],["G2316","God",26,29],["G3528","overcometh",30,40],["G2889","the world",41,50],["G2532","and",52,55],["G3778","this",56,60],["G2076","is",61,63],["G3529","the victory",64,75],["G3528","that overcometh",76,91],["G2889","the world",92,101],["G2257","even our",103,111],["G4102","faith",112,117]]},"5:5":{"text":"Who is he that overcometh the world, but he that believeth that Jesus is the Son of God?","words":[["G5101","Who",0,3],["G2076","is",4,6],["G3528","he that overcometh",7,25],["G2889","the world",26,35],["G1508","but",37,40],["G4100","he that believeth",41,58],["G3754","that",59,63],["G2424","Jesus",64,69],["G2076","is",70,72],["G5207","the Son",73,80],["G2316","of God",81,87]]},"5:6":{"text":"This is he that came by water and blood, even Jesus Christ; not by water only, but by water and blood. And it is the Spirit that beareth witness, because the Spirit is truth.","words":[["G3778","This",0,4],["G2076","is",5,7],["G2064","he that came",8,20],["G1223","by",21,23],["G5204","water",24,29],["G2532","and",30,33],["G0129","blood",34,39],["G2424","even Jesus",41,51],["G5547","Christ",52,58],["G3756","not",60,63],["G1722","by",64,66],["G5204","water",67,72],["G3440","only",73,77],["G0235","but",79,82],["G1722","by",83,85],["G5204","water",86,91],["G2532","and",92,95],["G0129","blood",96,101],["G2532","And",103,106],["G2076","it is",107,112],["G4151","the Spirit",113,123],["G3140","that beareth witness",124,144],["G3754","because",146,153],["G4151","the Spirit",154,164],["G2076","is",165,167],["G0225","truth",168,173]]},"5:7":{"text":"For there are three that bear record in heaven, the Father, the Word, and the Holy Ghost: and these three are one.","words":[["G3754","For",0,3],["G1526","there are",4,13],["G5140","three",14,19],["G3140","that bear record",20,36],["G1722","in",37,39],["G3772","heaven",40,46],["G3962","the Father",48,58],["G3056","the Word",60,68],["G2532","and",70,73],["G0040","the Holy",74,82],["G4151","Ghost",83,88],["G2532","and",90,93],["G3778","these",94,99],["G5140","three",100,105],["G1526","are",106,109],["G1520","one",110,113]]},"5:8":{"text":"And there are three that bear witness in earth, the spirit, and the water, and the blood: and these three agree in one.","words":[["G2532","And",0,3],["G1526","there are",4,13],["G5140","three",14,19],["G3140","that bear witness",20,37],["G1722","in",38,40],["G1093","earth",41,46],["G4151","the spirit",48,58],["G2532","and",60,63],["G5204","the water",64,73],["G2532","and",75,78],["G0129","the blood",79,88],["G2532","and",90,93],["G5140","these three",94,105],["G1526","agree",106,111],["G1519","in",112,114],["G1520","one",115,118]]},"5:9":{"text":"If we receive the witness of men, the witness of God is greater: for this is the witness of God which he hath testified of his Son.","words":[["G1487","If",0,2],["G2983","we receive",3,13],["G3141","the witness",14,25],["G0444","of men",26,32],["G3141","the witness",34,45],["G2316","of God",46,52],["G2076","is",53,55],["G3187","greater",56,63],["G3754","for",65,68],["G3778","this",69,73],["G2076","is",74,76],["G3141","the witness",77,88],["G2316","of God",89,95],["G3739","which",96,101],["G3140","he hath testified",102,119],["G4012","of",120,122],["G0846","his",123,126],["G5207","Son",127,130]]},"5:10":{"text":"He that believeth on the Son of God hath the witness in himself: he that believeth not God hath made him a liar; because he believeth not the record that God gave of his Son.","words":[["G4100","He that believeth",0,17],["G1519","on",18,20],["G5207","the Son",21,28],["G2316","of God",29,35],["G2192","hath",36,40],["G3141","the witness",41,52],["G1722","in",53,55],["G1438","himself",56,63],["G4100","he that believeth",65,82],["G3361","not",83,86],["G2316","God",87,90],["G4160","hath made",91,100],["G0846","him",101,104],["G5583","a liar",105,111],["G3754","because",113,120],["G4100","he believeth",121,133],["G3756","not",134,137],["G1519","not",134,137],["G3141","the record",138,148],["G3739","that",149,153],["G2316","God",154,157],["G3140","gave",158,162],["G4012","of",163,165],["G0846","his",166,169],["G5207","Son",170,173]]},"5:11":{"text":"And this is the record, that God hath given to us eternal life, and this life is in his Son.","words":[["G2532","And",0,3],["G3778","this",4,8],["G2076","is",9,11],["G3141","the record",12,22],["G3754","that",24,28],["G2316","God",29,32],["G1325","hath given",33,43],["G2254","to us",44,49],["G0166","eternal",50,57],["G2222","life",58,62],["G2532","and",64,67],["G3778","this",68,72],["G2222","life",73,77],["G2076","is",78,80],["G1722","in",81,83],["G0846","his",84,87],["G5207","Son",88,91]]},"5:12":{"text":"He that hath the Son hath life; and he that hath not the Son of God hath not life.","words":[["G2192","He that hath",0,12],["G5207","the Son",13,20],["G2192","hath",21,25],["G2222","life",26,30],["G2192","and he that hath",32,48],["G3361","not",49,52],["G5207","the Son",53,60],["G2316","of God",61,67],["G2192","hath",68,72],["G3756","not",73,76],["G2222","life",77,81]]},"5:13":{"text":"These things have I written unto you that believe on the name of the Son of God; that ye may know that ye have eternal life, and that ye may believe on the name of the Son of God.","words":[["G5023","These things",0,12],["G1125","have I written",13,27],["G5213","unto you",28,36],["G4100","that believe",37,49],["G1519","on",50,52],["G3686","the name",53,61],["G5207","of the Son",62,72],["G2316","of God",73,79],["G2443","that",81,85],["G1492","ye may know",86,97],["G3754","that ye",98,105],["G2192","have",106,110],["G0166","eternal",111,118],["G2222","life",119,123],["G2532","and",125,128],["G2443","that",129,133],["G4100","ye may believe",134,148],["G1519","on",149,151],["G3686","the name",152,160],["G5207","of the Son",161,171],["G2316","of God",172,178]]},"5:14":{"text":"And this is the confidence that we have in him, that, if we ask any thing according to his will, he heareth us:","words":[["G2532","And",0,3],["G3778","this",4,8],["G2076","is",9,11],["G3954","the confidence",12,26],["G3739","that",27,31],["G2192","we have",32,39],["G4314","in",40,42],["G0846","him",43,46],["G3754","that",48,52],["G1437","if",54,56],["G0154","we ask",57,63],["G5100","any thing",64,73],["G2596","according",74,83],["G0846","to his",84,90],["G2307","will",91,95],["G0191","he heareth",97,107],["G2257","us",108,110]]},"5:15":{"text":"And if we know that he hear us, whatsoever we ask, we know that we have the petitions that we desired of him.","words":[["G2532","And",0,3],["G1437","if",4,6],["G1492","we know",7,14],["G3754","that",15,19],["G0191","he hear",20,27],["G2257","us",28,30],["G3739","whatsoever",32,42],["G0302","whatsoever",32,42],["G0154","we ask",43,49],["G1492","we know",51,58],["G3754","that",59,63],["G2192","we have",64,71],["G0155","the petitions",72,85],["G3739","that",86,90],["G0154","we desired",91,101],["G3844","of",102,104],["G0846","him",105,108]]},"5:16":{"text":"If any man see his brother sin a sin which is not unto death, he shall ask, and he shall give him life for them that sin not unto death. There is a sin unto death: I do not say that he shall pray for it.","words":[["G1437","If",0,2],["G5100","any man",3,10],["G1492","see",11,14],["G0846","his",15,18],["G0080","brother",19,26],["G0264","sin",27,30],["G0266","a sin",31,36],["G3361","which is not",37,49],["G4314","unto",50,54],["G2288","death",55,60],["G0154","he shall ask",62,74],["G2532","and",76,79],["G1325","he shall give",80,93],["G0846","him",94,97],["G2222","life",98,102],["G0264","for them that sin",103,120],["G3361","not",121,124],["G4314","unto",125,129],["G2288","death",130,135],["G2076","There is",137,145],["G0266","a sin",146,151],["G4314","unto",152,156],["G2288","death",157,162],["G3756","I do not",164,172],["G3004","say",173,176],["G2443","that",177,181],["G2065","he shall pray",182,195],["G4012","for",196,199],["G1565","it",200,202]]},"5:17":{"text":"All unrighteousness is sin: and there is a sin not unto death.","words":[["G3956","All",0,3],["G0093","unrighteousness",4,19],["G2076","is",20,22],["G0266","sin",23,26],["G2532","and",28,31],["G2076","there is",32,40],["G0266","a sin",41,46],["G3756","not",47,50],["G4314","unto",51,55],["G2288","death",56,61]]},"5:18":{"text":"We know that whosoever is born of God sinneth not; but he that is begotten of God keepeth himself, and that wicked one toucheth him not.","words":[["G1492","We know",0,7],["G3754","that",8,12],["G3956","whosoever",13,22],["G1080","is born",23,30],["G1537","of",31,33],["G2316","God",34,37],["G0264","sinneth",38,45],["G3756","not",46,49],["G0235","but",51,54],["G1080","he that is begotten",55,74],["G1537","of",75,77],["G2316","God",78,81],["G5083","keepeth",82,89],["G1438","himself",90,97],["G2532","and",99,102],["G4190","that wicked one",103,118],["G0680","toucheth",119,127],["G0846","him",128,131],["G3756","not",132,135]]},"5:19":{"text":"And we know that we are of God, and the whole world lieth in wickedness.","words":[["G1492","And we know",0,11],["G3754","that",12,16],["G2070","we are",17,23],["G1537","of",24,26],["G2316","God",27,30],["G2532","and",32,35],["G3650","the whole",36,45],["G2889","world",46,51],["G2749","lieth",52,57],["G1722","in",58,60],["G4190","wickedness",61,71]]},"5:20":{"text":"And we know that the Son of God is come, and hath given us an understanding, that we may know him that is true, and we are in him that is true, even in his Son Jesus Christ. This is the true God, and eternal life.","words":[["G1161","And",0,3],["G1492","we know",4,11],["G3754","that",12,16],["G5207","the Son",17,24],["G2316","of God",25,31],["G2240","is come",32,39],["G2532","and",41,44],["G1325","hath given",45,55],["G2254","us",56,58],["G1271","an understanding",59,75],["G2443","that",77,81],["G1097","we may know",82,93],["G0228","him that is true",94,110],["G2532","and",112,115],["G2070","we are",116,122],["G1722","in",123,125],["G0228","him that is true",126,142],["G1722","even in",144,151],["G0846","his",152,155],["G5207","Son",156,159],["G2424","Jesus",160,165],["G5547","Christ",166,172],["G3778","This",174,178],["G2076","is",179,181],["G0228","the true",182,190],["G2316","God",191,194],["G2532","and",196,199],["G0166","eternal",200,207],["G2222","life",208,212]]},"5:21":{"text":"Little children, keep yourselves from idols. Amen.","words":[["G5040","Little children",0,15],["G5442","keep",17,21],["G1438","yourselves",22,32],["G0575","from",33,37],["G1497","idols",38,43],["G0281","Amen",45,49]]}}};
